"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import {
  triggerShake,
  getRandomComplete,
  getRandomEncourage,
} from "@/lib/learningMessages";

// ===== 各年份 2 月天数 =====
const YEARS = [
  { year: 2020, days: 29, leap: true },
  { year: 2021, days: 28, leap: false },
  { year: 2022, days: 28, leap: false },
  { year: 2023, days: 28, leap: false },
  { year: 2024, days: 29, leap: true },
  { year: 2025, days: 28, leap: false },
  { year: 2026, days: 28, leap: false },
  { year: 2027, days: 28, leap: false },
  { year: 2028, days: 29, leap: true },
] as const;

// ===== 判断题 =====
interface Question {
  q: string;
  hint: string;
  options: { label: string; value: number }[];
  answer: number; // 正确选项的 value
}

const QUESTIONS: Question[] = [
  {
    q: "2032 年是闰年吗？",
    hint: "2032 ÷ 4 = 508，正好整除 → 是闰年",
    options: [
      { label: "是", value: 0 },
      { label: "不是", value: 1 },
    ],
    answer: 0,
  },
  {
    q: "2030 年是闰年吗？",
    hint: "2030 ÷ 4 = 507.5，不能整除 → 是平年",
    options: [
      { label: "是", value: 0 },
      { label: "不是", value: 1 },
    ],
    answer: 1,
  },
  {
    q: "闰年比平年多几天？",
    hint: "闰年 2 月有 29 天，平年 2 月有 28 天，29 − 28 = ?",
    options: [
      { label: "1 天", value: 0 },
      { label: "2 天", value: 1 },
      { label: "3 天", value: 2 },
      { label: "4 天", value: 3 },
    ],
    answer: 0,
  },
];

type Phase = "discover" | "quiz" | "done";
type Feedback = { type: "ok" | "warn"; text: string } | null;

export default function TransformPage() {
  const [phase, setPhase] = useState<Phase>("discover");
  const [showMore, setShowMore] = useState(false);
  const [currentQ, setCurrentQ] = useState(0);
  const [showHint, setShowHint] = useState(false);
  const [feedback, setFeedback] = useState<Feedback>(null);
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const nextStep = getNextStep("calendar", "transform");
  // discover 阶段展示的年份数量
  const visibleYears = showMore ? YEARS : YEARS.slice(0, 5);
  const leapYears = YEARS.filter((y) => y.leap).map((y) => y.year);

  const showFeedback = (fb: NonNullable<Feedback>, ms = 1600) => {
    setFeedback(fb);
    window.setTimeout(() => setFeedback(null), ms);
  };

  const handleAnswer = (qIdx: number, value: number) => {
    const q = QUESTIONS[qIdx];
    if (value === q.answer) {
      showFeedback({ type: "ok", text: "✓ 2032能被4整除" });
      window.setTimeout(() => {
        setFeedback(null);
        setShowHint(false);
        if (qIdx + 1 >= QUESTIONS.length) {
          setPhase("done");
        } else {
          setCurrentQ(qIdx + 1);
        }
      }, 900);
    } else {
      const el = document.getElementById("quiz-card");
      triggerShake(el);
      setShowHint(true);
      showFeedback({ type: "warn", text: getRandomEncourage() });
    }
  };

  return (
    <StepShell topicId="calendar" stepId="transform">
      {/* ===== 阶段 1：发现规律 ===== */}
      {phase === "discover" && (
        <div className="space-y-5">
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center">
            <p className="text-[var(--text)]">🗓️ 看一看这些年 2 月有多少天</p>
            <p className="mt-1 text-sm text-[var(--text-secondary)]">
              闰年的 2 月有 29 天，平年的 2 月只有 28 天
            </p>
          </div>

          {/* 年份卡片 */}
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            <div className="grid grid-cols-3 gap-3 sm:grid-cols-5">
              {visibleYears.map((y) => (
                <div
                  key={y.year}
                  className={`animate-float-in rounded-[var(--radius-sm)] border-2 p-3 text-center transition-all ${
                    y.leap
                      ? "border-[var(--accent2)] bg-[var(--accent2)]/10"
                      : "border-[var(--border)] bg-[var(--bg-soft)]"
                  }`}
                >
                  <div className="text-sm font-bold text-[var(--text)]">{y.year} 年</div>
                  <div className="mt-1 text-xs text-[var(--text-muted)]">2 月</div>
                  <div
                    className="mt-1 text-2xl font-extrabold"
                    style={{ color: y.leap ? "var(--accent2)" : "var(--text-secondary)" }}
                  >
                    {y.days}
                    <span className="text-sm font-medium text-[var(--text-muted)]">天</span>
                  </div>
                  <div
                    className={`mt-1 text-xs font-semibold ${
                      y.leap ? "text-[var(--accent2)]" : "text-[var(--text-muted)]"
                    }`}
                  >
                    {y.leap ? "闰年 ✓" : "平年"}
                  </div>
                </div>
              ))}
            </div>

            {/* 查看更多 / 规律提示 */}
            <div className="mt-5 text-center">
              {!showMore ? (
                <button
                  onClick={() => setShowMore(true)}
                  className="rounded-full bg-[var(--primary)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-md)] transition-all hover:scale-105"
                >
                  查看更多年份 →
                </button>
              ) : (
                <div className="animate-float-in space-y-3">
                  <div className="inline-block rounded-full bg-[var(--accent3)]/20 px-5 py-2 text-sm font-bold text-[var(--text)]">
                    🔍 发现规律：每 4 年就有一个闰年！
                  </div>
                  {/* 闰年间隔示意 */}
                  <div className="flex flex-wrap items-center justify-center gap-2 text-sm">
                    {leapYears.map((y, i) => (
                      <span key={y} className="flex items-center gap-2">
                        <span className="rounded-full bg-[var(--accent2)] px-3 py-1 font-bold text-white">
                          {y}
                        </span>
                        {i < leapYears.length - 1 && (
                          <span className="text-[var(--text-muted)]">＋4 年 →</span>
                        )}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* 进入判断题 */}
          {showMore && (
            <div className="flex justify-center animate-float-in">
              <button
                onClick={() => setPhase("quiz")}
                className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                我来判断闰年 →
              </button>
            </div>
          )}
        </div>
      )}

      {/* ===== 阶段 2：判断闰年 ===== */}
      {phase === "quiz" && (
        <div className="space-y-5">
          {/* 进度 + 反馈 */}
          <div className="flex min-h-[28px] items-center justify-between gap-3">
            <span className="text-sm text-[var(--text-secondary)]">
              第 <strong className="text-[var(--accent-dark)]">{currentQ + 1}</strong> / {QUESTIONS.length} 题
            </span>
            {feedback && (
              <span
                className={`rounded-full px-4 py-1 text-sm font-medium animate-float-in ${
                  feedback.type === "ok"
                    ? "bg-[var(--signal-success)]/15 text-[var(--signal-success)]"
                    : "bg-[var(--signal-shake)]/15 text-[var(--signal-shake)]"
                }`}
              >
                {feedback.text}
              </span>
            )}
          </div>

          {/* 题目卡片 */}
          <div
            id="quiz-card"
            className="rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]"
          >
            <p className="mb-4 text-center text-lg font-bold text-[var(--text)]">
              {QUESTIONS[currentQ].q}
            </p>
            <div
              className={`grid gap-3 ${
                QUESTIONS[currentQ].options.length === 2 ? "grid-cols-2" : "grid-cols-2 sm:grid-cols-4"
              }`}
            >
              {QUESTIONS[currentQ].options.map((opt) => (
                <button
                  key={opt.value}
                  onClick={() => handleAnswer(currentQ, opt.value)}
                  className="rounded-lg border border-[var(--border)] bg-[var(--bg-soft)] px-4 py-3 text-sm font-medium text-[var(--text)] transition-all hover:scale-105 hover:border-[var(--primary-light)] hover:bg-[var(--signal-focus)]/10"
                >
                  {opt.label}
                </button>
              ))}
            </div>

            {/* 提示（答错后出现） */}
            {showHint && (
              <div className="mt-4 animate-float-in rounded-lg bg-[var(--accent3)]/15 px-4 py-2 text-center text-sm text-[var(--text-secondary)]">
                💡 {QUESTIONS[currentQ].hint}
              </div>
            )}
          </div>

          {/* 规律回顾 */}
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center text-sm text-[var(--text-secondary)]">
            小窍门：年份 ÷ 4 能整除就是闰年，2 月有 <strong>29</strong> 天；
            不能整除就是平年，2 月有 <strong>28</strong> 天。
          </div>
        </div>
      )}

      {/* ===== 完成阶段 ===== */}
      {phase === "done" && (
        <div className="space-y-4">
          <div className="rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)] animate-float-in">
            <div className="mb-2 text-4xl">🌟</div>
            <p className="text-lg font-semibold text-[var(--text)]">{completeMsg}</p>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              你掌握了闰年的秘密：每 4 年一个闰年，闰年比平年多 1 天！
            </p>
          </div>

          <div className="flex flex-wrap justify-center gap-4">
            <button
              onClick={() => {
                setPhase("discover");
                setShowMore(false);
                setCurrentQ(0);
                setShowHint(false);
                setFeedback(null);
              }}
              className="rounded-full border border-[var(--border)] px-6 py-3 font-medium text-[var(--text-secondary)] transition-all hover:bg-[var(--bg-soft)]"
            >
              再玩一次
            </button>
            {nextStep && (
              <Link
                href={nextStep.path}
                className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                下一步：{nextStep.label} →
              </Link>
            )}
          </div>
        </div>
      )}
    </StepShell>
  );
}
